public static IList<int> AtLeastNOverThree(int[] nums)
{
    int threshold = nums.Length / 3;          // floor(n/3)
    var counts = new Dictionary<int, int>();
    foreach (int x in nums)
        counts[x] = counts.GetValueOrDefault(x) + 1;

    var res = new List<int>();
    foreach (var kv in counts)
        if (kv.Value >= threshold)            // 'at least' -> use >=
            res.Add(kv.Key);

    res.Sort();                               // [1,2,3] rather than hash order
    return res;
}

