public static (string reversed, Dictionary<string,int> counts) ReverseWords(string sentence)
{
    string[] words = sentence.Split((char[])null!,
        StringSplitOptions.RemoveEmptyEntries);

    var counts = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
    foreach (var w in words)
    {
        counts.TryGetValue(w, out int c);
        counts[w] = c + 1;
    }

    Array.Reverse(words); // manual: swap two-pointer if Reverse is banned
    return (string.Join(' ', words), counts);
}

