// Merge sort on a singly linked list (top-down)
public class Node { public int Val; public Node? Next; }

public static Node? Sort(Node? head)
{
    if (head?.Next == null) return head;
    // split with slow/fast pointers
    Node slow = head, fast = head.Next;
    while (fast?.Next != null) { slow = slow.Next!; fast = fast.Next.Next; }
    Node mid = slow.Next!; slow.Next = null;
    return Merge(Sort(head), Sort(mid));
}

static Node? Merge(Node? a, Node? b)
{
    var dummy = new Node(); var tail = dummy;
    while (a != null && b != null)
    {
        if (a.Val <= b.Val) { tail.Next = a; a = a.Next; }
        else { tail.Next = b; b = b.Next; }
        tail = tail.Next;
    }
    tail.Next = a ?? b;
    return dummy.Next;
}

// Doubly linked node for back/forward navigation
public class Page
{
    public string Url = "";
    public Page? Prev, Next;
}

public class History
{
    private Page? current;
    public void Visit(string url)
    {
        var p = new Page { Url = url, Prev = current };
        if (current != null) current.Next = p; // forward history truncated
        current = p;
    }
    public string? Back()    => (current?.Prev != null) ? (current = current.Prev).Url : null;
    public string? Forward() => (current?.Next != null) ? (current = current.Next).Url : null;
}

