-- Parameterized query (T-SQL)
DECLARE @N INT = 3;

SELECT MAX(Salary) AS NthHighestSalary
FROM (
    SELECT Salary, DENSE_RANK() OVER (ORDER BY Salary DESC) AS rnk
    FROM Employee
) t
WHERE rnk = @N;

-- As a reusable function
CREATE FUNCTION dbo.GetNthSalary(@N INT)
RETURNS INT AS
BEGIN
    RETURN (
        SELECT DISTINCT Salary
        FROM (
            SELECT Salary, DENSE_RANK() OVER (ORDER BY Salary DESC) AS rnk
            FROM Employee
        ) t
        WHERE rnk = @N
    );
END;

